import click
from click.shell_completion import ShellComplete

@click.group(context_settings={'validate_nesting': True})
def cli():
    pass

@cli.group()
def sub():
    pass

@sub.command()
@click.option('--name')
def leaf(name):
    pass

comp = ShellComplete(cli, {}, 'cli', '_CLI_COMPLETE')
completions = comp.get_completions(['sub', 'leaf'], '--n')
print([c.value for c in completions])
print('shell completion with validate_nesting=True context_settings works fine')
"

