import click
from click.testing import CliRunner

@click.group(context_settings={'validate_nesting': True})
def cli():
    pass

@cli.group()
def sub():
    pass

@sub.command()
@click.option('--name', default='world')
def leaf(name):
    click.echo(f'hello {name}')

runner = CliRunner()
result = runner.invoke(cli, ['sub', 'leaf', '--name', 'click'])
print(result.output)
print('exit code', result.exit_code)
if result.exception:
    import traceback
    traceback.print_exception(type(result.exception), result.exception, result.exception.__traceback__)
"

