import click
from click.testing import CliRunner

@click.group(context_settings={'validate_nesting': True})
@click.pass_context
def cli(ctx):
    pass

@cli.command()
@click.pass_context
def a(ctx):
    ctx.invoke(b)
    click.echo('a done')

@cli.command()
def b():
    click.echo('b')

runner = CliRunner()
result = runner.invoke(cli, ['a'])
print(result.output)
print('exit code', result.exit_code)
if result.exception:
    import traceback
    traceback.print_exception(type(result.exception), result.exception, result.exception.__traceback__)
"

